(18823,'AC69216DCB41E17F0972A694A3FE4B26',NULL,10951,'6283849283134','outgoing','Tamu VVIP (Duduk Bawah Tenda)\n1. Bapak Siswo Sumarjono\n2. Bapak Sunarto\n3. R. Asmuni\n4. Bapk Yusuf Wibisana\n5. Bu Kitri\n6. Ibu Dwi Hardanti\n7. Ibu Jamilatun\n8. Ibu Harni\n9. Bapak Sapardi\n10. Ibu Siti Yumaroh\n11. Bapak Purwoharjono\n12. Bapak Nur RT\n13. Bapak Masiman\n14. Bapak Muh Yasir\n15. Bapak H. Sumarjiyono\n16. Bapak R. Djuwani\n17. Bapak Sarjimin\n18. Bapak Supardi\nPelaksanaan Upacara Pukul 07.30 \nTempat : Lapangan Gading Jati\nOperator Sound : Hartono/Pemuda','text','Septi Juliani','','','2026-07-18 00:35:30','2026-07-18 00:35:30'),
